17: package org.apache.kafka.clients.consumer.internals.metrics;
18: 
19: import org.apache.kafka.common.MetricName;
20: import org.apache.kafka.common.metrics.Measurable;
21: import org.apache.kafka.common.metrics.Metrics;
22: import org.apache.kafka.common.metrics.Sensor;
23: import org.apache.kafka.common.metrics.stats.Avg;
24: import org.apache.kafka.common.metrics.stats.CumulativeCount;
25: import org.apache.kafka.common.metrics.stats.CumulativeSum;
26: import org.apache.kafka.common.metrics.stats.Max;
27: import org.apache.kafka.common.metrics.stats.Rate;
28: import org.apache.kafka.common.metrics.stats.WindowedCount;
29: 
30: import java.util.concurrent.TimeUnit;
31: 
32: import static org.apache.kafka.clients.consumer.internals.ConsumerUtils.CONSUMER_METRIC_GROUP_PREFIX;
33: import static org.apache.kafka.clients.consumer.internals.ConsumerUtils.COORDINATOR_METRICS_SUFFIX;
34: 
35: public final class ConsumerRebalanceMetricsManager extends RebalanceMetricsManager {
36:     private final Sensor successfulRebalanceSensor;
37:     private final Sensor failedRebalanceSensor;
38: 
39:     public final MetricName rebalanceLatencyAvg;
40:     public final MetricName rebalanceLatencyMax;
41:     public final MetricName rebalanceLatencyTotal;
42:     public final MetricName rebalanceTotal;
43:     public final MetricName rebalanceRatePerHour;
44:     public final MetricName lastRebalanceSecondsAgo;
45:     public final MetricName failedRebalanceTotal;
46:     public final MetricName failedRebalanceRate;
47:     private long lastRebalanceEndMs = -1L;
48:     private long lastRebalanceStartMs = -1L;
49: 
50:     public ConsumerRebalanceMetricsManager(Metrics metrics) {
51:         super(CONSUMER_METRIC_GROUP_PREFIX + COORDINATOR_METRICS_SUFFIX);
52: 
53:         rebalanceLatencyAvg = createMetric(metrics, "rebalance-latency-avg",
54:                 "The average time in ms taken for a group to complete a rebalance");
55:         rebalanceLatencyMax = createMetric(metrics, "rebalance-latency-max",
56:                 "The max time in ms taken for a group to complete a rebalance");
57:         rebalanceLatencyTotal = createMetric(metrics, "rebalance-latency-total",
58:                 "The total number of milliseconds spent in rebalances");
59:         rebalanceTotal = createMetric(metrics, "rebalance-total",
60:                 "The total number of rebalance events");
61:         rebalanceRatePerHour = createMetric(metrics, "rebalance-rate-per-hour",
62:                 "The number of rebalance events per hour");
63:         failedRebalanceTotal = createMetric(metrics, "failed-rebalance-total",
64:                 "The total number of failed rebalance events");
65:         failedRebalanceRate = createMetric(metrics, "failed-rebalance-rate-per-hour",
66:                 "The number of failed rebalance events per hour");
67: 
68:         successfulRebalanceSensor = metrics.sensor("rebalance-latency");
69:         successfulRebalanceSensor.add(rebalanceLatencyAvg, new Avg());
70:         successfulRebalanceSensor.add(rebalanceLatencyMax, new Max());
71:         successfulRebalanceSensor.add(rebalanceLatencyTotal, new CumulativeSum());
72:         successfulRebalanceSensor.add(rebalanceTotal, new CumulativeCount());
73:         successfulRebalanceSensor.add(rebalanceRatePerHour, new Rate(TimeUnit.HOURS, new WindowedCount()));
74: 
75:         failedRebalanceSensor = metrics.sensor("failed-rebalance");
76:         failedRebalanceSensor.add(failedRebalanceTotal, new CumulativeSum());
77:         failedRebalanceSensor.add(failedRebalanceRate, new Rate(TimeUnit.HOURS, new WindowedCount()));
78: 
79:         Measurable lastRebalance = (config, now) -> {
80:             if (lastRebalanceEndMs == -1L)
81:                 return -1d;
82:             else
83:                 return TimeUnit.SECONDS.convert(now - lastRebalanceEndMs, TimeUnit.MILLISECONDS);
84:         };
85:         lastRebalanceSecondsAgo = createMetric(metrics,
86:                 "last-rebalance-seconds-ago",
87:                 "The number of seconds since the last rebalance event");
88:         metrics.addMetric(lastRebalanceSecondsAgo, lastRebalance);
89:     }
90: 
91:     public void recordRebalanceStarted(long nowMs) {
92:         lastRebalanceStartMs = nowMs;
93:     }
94: 
95:     public void recordRebalanceEnded(long nowMs) {
96:         lastRebalanceEndMs = nowMs;
97:         successfulRebalanceSensor.record(nowMs - lastRebalanceStartMs);
98:     }
99: 
100:     public void maybeRecordRebalanceFailed() {
101:         if (lastRebalanceStartMs <= lastRebalanceEndMs)
102:             return;
103:         failedRebalanceSensor.record();
104:     }
105: 
106:     public boolean rebalanceStarted() {
107:         return lastRebalanceStartMs > lastRebalanceEndMs;
